module RefModule(rst, clk, test, sync, freq, o);parameter WID = 32; 
input rst;
input clk;
input test;
input sync;
input [WID-1:0] freq;   
output [WID-1:0] o;

reg [WID-1:0] unused_acc;

always @(posedge clk)
if (rst)
    unused_acc <= 0;
else begin
    if (~test) begin
        if (sync)
            unused_acc <= 0;
        else
            unused_acc <= unused_acc + freq;
    end
    else
        unused_acc <= 0;
end

assign o = unused_acc;

endmodule
